INSERT INTO public.photos VALUES (21374, 'Callejâ”œâ”‚n del Perro 1911', 'Instantâ”œأ­nea del callejâ”œâ”‚n del Perro, junto a la plaza de San Miguel de Zaragoza, tras la muerte el sâ”œأ­bado 16 de septiembre de 1911 de Francisco â”œأ¼lvarez, presidente de la sociedad de canteros, a manos de la Guardia Civil, durante la huelga revolucionaria convocada por la CNT. El nombre de esta vâ”œآ،a se atribuye a un perro propiedad de un judâ”œآ،o que allâ”œآ، habitaba, que atacaba a los cristianos y fue sacrificado por orden de la Inquisiciâ”œâ”‚n.', 1911, 1911, 1911, 'Anos 10', 'CENTRO', 41.65009800, -0.87561300, '0101000020E6100000747ADE8D0505ECBFF698486936D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15672881248.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15672881248.webp', 'https://www.flickr.com/photos/zaragozaantigua/15672881248/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21432, 'Callejâ”œâ”‚n del Perro 1911', 'Imagen capturada en el antiguo callejâ”œâ”‚n del Perro (barrio de San Miguel) con motivo de los violentos sucesos allâ”œآ، acontecidos durante la huelga de abastecimiento y contra la guerra colonial en Marruecos del mes de septiembre. Tras una carga a caballerâ”œآ،a de la Guardia Civil en este recoleto fondo de saco, el presidente de la Asociaciâ”œâ”‚n de Canteros, Francisco â”œأ¼lvarez, resultâ”œâ”‚ muerto, y otros sindicalistas heridos graves. El cuerpo sin vida ha sido ya retirado, y los auxiliares de la Cruz Roja indican con sus cuerpos hacia el lugar del deceso, junto a la puerta del fondo, correspondiente con el nâ”¬â•‘ 8 acc.â”¬â•‘. A la izquierda, el nâ”¬â•‘ 7 acc.â”¬â•‘, y a la derecha el nâ”¬â•‘ 6. El nombre de este vial perdura en nuestros dâ”œآ،as para recordar el fantâ”œأ­stico suceso que dice que en pleno siglo XVI, la Edad de Oro de la ciudad, dicen, la Inquisiciâ”œâ”‚n acusâ”œâ”‚ a un perro residente en este callejâ”œâ”‚n de tener un dueâ”œâ–’o judâ”œآ،o que le habâ”œآ،a aleccionado para discernir entre fieles a la Torâ”œأ­, y gentiles, a los que atacaba alevosamente de forma especial por la noche, al amparo de las sombras, cuando el perro-Golem atacaba con mâ”œأ­s saâ”œâ–’a. El perro delincuente fue condenado a muerte, y su inductor y câ”œâ”‚mplice dueâ”œâ–’o fue recluido en los calabozos de la Aljaferâ”œآ،a para purgar sus graves delitos. Fuente visual: El fotâ”œâ”‚grafo Luis Gandâ”œâ•‘ Mercadal. Una crâ”œâ”‚nica visual 1910-1930.', 1911, 1911, 1911, 'Anos 10', 'CENTRO', 41.65011000, -0.87554600, '0101000020E61000008198840B7904ECBFBA66F2CD36D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35993678403.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35993678403.webp', 'https://www.flickr.com/photos/zaragozaantigua/35993678403/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21457, 'Petit Park c.1918', 'Inâ”œآ®dita imagen del acceso al "Campo de Espectâ”œأ­culos" del "Petit Park Pro-Infancia" en la prolongaciâ”œâ”‚n de la calle de los Sitios (tramo entre las calles de Jerâ”œâ”‚nimo Zurita y Felipe Sanclemente), gran centro de ocio abierto en 1916 en la zona pendiente de urbanizaciâ”œâ”‚n del que fuera recinto de la Exposiciâ”œâ”‚n Hispano-Francesa de 1908. Durante el dâ”œآ،a este "Campo de Espectâ”œأ­culos" se abrâ”œآ،a a conciertos y fiestas infantiles, y por la tarde y noche se convertâ”œآ،a en escenario de actuaciones para pâ”œâ•‘blico adulto. Por aquâ”œآ، pasâ”œâ”‚ la prestigiosa compaâ”œâ–’â”œآ،a de "varietâ”œآ®s" de G. Spinetto y su portentoso y joven ventrâ”œآ،locuo Wenceslao Moreno Centeno, que tras hacer las amâ”œآ®ricas, primero del sur y luego del norte, en los primeros aâ”œâ–’os treinta, adquiriâ”œâ”‚ gran prestigio, renombre y popularidad en USA durante dâ”œآ®cadas como "Seâ”œâ–’or Wences".', 1918, 1918, 1918, 'Anos 10', 'CENTRO', 41.64890500, -0.87942100, '0101000020E6100000BA4C4D823724ECBFFE9AAC510FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52047029163.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52047029163.webp', 'https://www.flickr.com/photos/zaragozaantigua/52047029163/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21487, 'Plaza de Emilio Castelar 1922', 'AHPZ. Archivo Fotogrâ”œأ­fico Julio Requejo. "Plaza de Castelar." 9 de octubre 1922. Hay espacios de la ciudad cuya denominaciâ”œâ”‚n ha sido especialmente variable, sin tener que pasar siquiera del siglo de historia, contradiciendo flagrantemente, con datos incontestables, esa castiza y rotunda sentencia local (menos que provinciana) que refiere que las cosas, como el nombre de una calle, de una plaza, han sido asâ”œآ، "de toda la vida". Tal es el caso de la Plaza de Castelar, que aquâ”œآ، aparece con cartel indicativo de la â”œآ®poca, para pasmo y transtorno de hueros iconâ”œâ”‚dulos.', 1922, 1922, 1922, 'Anos 20', 'CENTRO', 41.64890300, -0.87926500, '0101000020E6100000DE8E705AF022ECBF5DA3E5400FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15122200912.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15122200912.webp', 'https://www.flickr.com/photos/zaragozaantigua/15122200912/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21513, 'Colegio Gascâ”œâ”‚n y Marâ”œآ،n 1922', 'Miguel Faci Abad. 1922. "Zaragoza. Personaje desconocido en la galerâ”œآ،a del Colegio Gascâ”œâ”‚n y Marâ”œآ،n." Imagen, de espaldas, posiblemente de Miguel Antonio Faci, padre del fotâ”œâ”‚grafo autor de esta fotografâ”œآ،a, desde el interior de la galerâ”œآ،a del Colegio Gascâ”œâ”‚n y Marâ”œآ،n de la plaza de Castelar. Este edificio se realizâ”œâ”‚ en 1915 con proyecto del arquitecto municipal Josâ”œآ® de Yarza y Echenique. Entre las columnas, visual de los edificios herencia de la Expo 1908. Fuente visual: "Miguel y Gabriel Faci. Fotâ”œâ”‚grafos fundadores de la Real Sociedad Fotogrâ”œأ­fica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaciâ”œâ”‚n Provincial de Zaragoza, 1999.', 1922, 1922, 1922, 'Anos 20', 'CENTRO', 41.64937800, -0.87813100, '0101000020E61000002252D32EA619ECBFF65E7CD11ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15714000091.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15714000091.webp', 'https://www.flickr.com/photos/zaragozaantigua/15714000091/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21528, 'Plaza de Castelar 1921', 'Miguel Faci Abad. Imagen de la plaza de Castelar cuando estaba empezando a convertirse en el oasis verde heredero de la antigua huerta de Santa Engracia, tras los eventos de la Expo de 1908, mientras la urbanizaciâ”œâ”‚n de esta zona iba lentamente progresando. La tranquilidad apenas queda alterada por el sosegado paso del carro de uno de los aguadores de la ciudad. Al fondo, a la izquierda, los elevados andamios de la casa de Tomâ”œأ­s Castellano Echenique indican que la obra, proyectada por Teodoro Râ”œآ،os en 1920, va a ser recrecida sobre la marcha para alcanzar la notable altura que hoy presenta. Enfrente, al otro lado de la calle Sanclemente, sigue vacâ”œآ،o el solar propiedad de Alejandro Palomar de la Torre que unos aâ”œâ–’os despuâ”œآ®s ocuparâ”œأ­ el edificio del nâ”¬â•‘ 25, proyectado por Regino Borobio. Fuente visual: "Miguel y Gabriel Faci. Fotâ”œâ”‚grafos fundadores de la Real Sociedad Fotogrâ”œأ­fica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaciâ”œâ”‚n Provincial de Zaragoza, 1999.', 1921, 1921, 1921, 'Anos 20', 'CENTRO', 41.64886500, -0.87931300, '0101000020E610000022533E045523ECBF704221020ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18112919746.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18112919746.webp', 'https://www.flickr.com/photos/zaragozaantigua/18112919746/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21553, 'Plaza de Castelar c.1920', 'Vista de la plaza de Castelar tras la celebraciâ”œâ”‚n de la Exposiciâ”œâ”‚n Hispano Francesa de 1908. Se observa el Grupo Escolar Gascâ”œâ”‚n y Marâ”œآ،n, con la torre de la iglesia de San Miguel al fondo; la Escuela de Artes y Oficios; y el monumento a los Sitios. Fuente: AMZ.', 1920, 1920, 1920, 'Anos 20', 'CENTRO', 41.64886500, -0.87931300, '0101000020E610000022533E045523ECBF704221020ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21103415872.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21103415872.webp', 'https://www.flickr.com/photos/zaragozaantigua/21103415872/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25627, 'Gâ”œâ”‚mez Laguna 1970', 'Imagen de las instalaciones de la Sociedad Anâ”œâ”‚nima Farmacâ”œآ®utica Aragonesa (SAFA) de Zaragoza, en su despejada ubicaciâ”œâ”‚n de la novâ”œآ،sima avenida del Alcalde Luis Gâ”œâ”‚mez Laguna, cuando apenas era un vial de acceso a la antigua carretera de los Enlaces. SAFA fue constituida en 1919 para el comercio y distribuciâ”œâ”‚n de productos farmacâ”œآ®uticos y medicamentos, incluyendo algunos productos de factura propia, como las pastillas "Dispak" para la tos. Mâ”œأ­s tarde, se integrarâ”œآ،a en la mâ”œأ­s grande empresa Galenica Laboratorios, y luego en Alliance Healthcare, donde continâ”œâ•‘a, en otra ubicaciâ”œâ”‚n mâ”œأ­s norteâ”œâ–’a. En la imagen, el asfalto de la novâ”œآ،sima avenida apenas ha sido hollado y, al fondo, a la derecha, limpia vista de la Residencia Sanitaria "Josâ”œآ® Antonio" y del campo municipal de La Romareda, antes de completarse la urbanizaciâ”œâ”‚n del Polâ”œآ،gono Gran Vâ”œآ،a. Esta instalaciâ”œâ”‚n luego fue derribada, y en su lugar fue levantada a mediados de los aâ”œâ–’os 90 una gran urbanizaciâ”œâ”‚n vertical de 12 alturas, que incluye piscina al aire. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.64091200, -0.91196100, '0101000020E61000005247C7D5C82EEDBF96CE876709D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32988333735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32988333735.webp', 'https://www.flickr.com/photos/zaragozaantigua/32988333735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21561, 'Calle S. Miguel 1927', 'Imagen del extraâ”œâ–’o edificio del antiguo nâ”¬â•‘ 33 de la calle de San Miguel, esquinero con la calle de Mateo Flandro (izquierda), y catalogado como "arquitectura civil", y gracias. La radical alteridad de su fâ”œأ­brica, descontextualizada del entorno, se adelantâ”œâ”‚ unas cuantas dâ”œآ®cadas a su tiempo, aunque la piedra empleada le anclâ”œâ”‚ a antiguas ataduras ligadas al bullicioso subconsciente medieval que tanto pesa en esta ciudad. Esa aparente divergencia entre un aire demasiado moderno, y un pasado muy pesado, se solventâ”œâ”‚ emocionalmente con apelaciones a lo extraordinario, a la fantasâ”œآ،a y la quimera: otra casa con "duende". Improbables criaturas encadenadas, ectoplasmas demenciales y dejados, y sinfonâ”œآ،as de ruidos y proyecciones sombrâ”œآ،as, acompaâ”œâ–’aron el mundanal trasiego de las dâ”œآ®cadas en este tramo vial. Mientras tanto, de paso, la calle de San Miguel fue realineada y ensanchada para proporcionar accesos capaces al trâ”œأ­nsito mecanizado hacia la nueva plaza de Castelar como ensanche burguâ”œآ®s, y hacia el paseo de la Independencia. Asâ”œآ،, la casa de la izquierda, involuntario soporte publicitario, serâ”œأ­ derrribada y sustituida por una nueva, que deberâ”œأ­ actualizar el nomenclâ”œأ­tor, pues la calle del Agua mudarâ”œأ­ a "Mateo Flandro". Su vecina de la derecha aguantarâ”œأ­ hasta los aâ”œâ–’os 60, en que darâ”œأ­ el consecuente "estirâ”œâ”‚n" vertical, signo de los tiempos. Renumerado como 43, el pâ”œآ®treo edificio de la imagen, perdura. Fuente visual: Juan Mora Insa, DARA-AHPZ.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64990100, -0.87728500, '0101000020E6100000FBAE08FEB712ECBFA051BAF42FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22473452946.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22473452946.webp', 'https://www.flickr.com/photos/zaragozaantigua/22473452946/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21717, 'Proyecto Ayuntamiento 1930', 'Proyecto de Casa Consistorial para Zaragoza, en la plaza de Castelar, diseâ”œâ–’ado por el arquitecto Miguel â”œأ¼ngel Navarro, y aprobado en 1924. Su ubicaciâ”œâ”‚n estaba prevista en la manzana situada entre las calles de Sancho y Gil (izquierda) y Arquitecto Magdalena (derecha). Al fondo, el paseo de la Mina. La dilaciâ”œâ”‚n en el inicio de obras, sumado a las crecientes dificultades econâ”œâ”‚micas del consistorio para acometerlas tras el 14 de abril de 1931, dejâ”œâ”‚ en suspenso la ejecuciâ”œâ”‚n de este proyecto. Fuente: dara.aragon.es/', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.64886500, -0.87931300, '0101000020E610000022533E045523ECBF704221020ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19577247752.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19577247752.webp', 'https://www.flickr.com/photos/zaragozaantigua/19577247752/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
