INSERT INTO public.photos VALUES (21841, 'Pl. de Castelar 1938', 'Soleada imagen de un grupo de enfermeras posando durante el II Aâ”œâ–’o Triunfal en la terraza de las Clâ”œآ،nicas de la Cruz Roja chaflaneras entre la plaza de Castelar, que al poco tiempo serâ”œآ،a redenominada en homenaje al ausente Josâ”œآ® Antonio, y la calle de Sancho y Gil. La enfermera de la izquierda es S.A.R. la Serenâ”œآ،sima infanta doâ”œâ–’a Marâ”œآ،a de las Mercedes de Baviera y Borbâ”œâ”‚n, sobrina de Alfonso XIII que, exiliada en Alemania desde la proclamaciâ”œâ”‚n de la Segunda Repâ”œâ•‘blica Espaâ”œâ–’ola en 1931, habâ”œآ،a regresado tras el 18-19 de julio de 1936 a territorio liberado del comunismo, la juderâ”œآ،a y la masonerâ”œآ،a. Fuente visual: www.memoriademadrid.es/', 1938, 1938, 1938, 'Anos 30', 'CENTRO', 41.64958100, -0.87861500, '0101000020E610000021CD58349D1DECBF2E8D5F7825D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35173273576.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35173273576.webp', 'https://www.flickr.com/photos/zaragozaantigua/35173273576/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21942, 'San Miguel aâ”œâ–’os 40', 'Iglesia de San Miguel de los Navarros (Zaragoza), aguafuerte, Jesâ”œâ•‘s Fernâ”œأ­ndez Barrio, Diputaciâ”œâ”‚n de Zaragoza, c. 1945-1947. Fuente: web.dpz.es/arscatalogi.es/', 1940, 1940, 1949, 'Anos 40', 'CENTRO', 41.64918100, -0.87595700, '0101000020E6100000037976F9D607ECBFA017EE5C18D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15689394250.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15689394250.webp', 'https://www.flickr.com/photos/zaragozaantigua/15689394250/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22008, 'San Miguel c.1941', 'Dibujo representando el alzado de la cabecera de la iglesia parroquial de San Miguel de los Navarros tal y como hubiera quedado de realizarse la intervenciâ”œâ”‚n proyectada por Manuel Lorente en su etapa de Arquitecto-conservador de Monumentos Histâ”œâ”‚rico-Artâ”œآ،sticos de la Tercera Zona (Zaragoza, Huesca, Teruel, Navarra, Guipâ”œâ•‘zcoa, Vizcaya, â”œأ¼lava y Logroâ”œâ–’o). El elemento mâ”œأ­s novedoso de esta reforma hubiera sido, tal vez, la acusada reinterpretaciâ”œâ”‚n de la torre, tras ser despojada de su metâ”œأ­lico y caracteristico chapitel modernista y modelada al gusto estâ”œآ®tico regionalista y nacionalista del Râ”œآ®gimen. Fuente visual: arquitecto Manuel Lorente Junquera, AHPZ.', 1941, 1941, 1941, 'Anos 40', 'CENTRO', 41.64951900, -0.87615100, '0101000020E61000003F726BD26D09ECBFB890477023D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40078196625.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40078196625.webp', 'https://www.flickr.com/photos/zaragozaantigua/40078196625/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22044, 'Calle del Asalto 1951', 'La calle del Asalto, en el tramo comprendido entre la calle del Heroâ”œآ،smo y donde a la derecha y fuera de plano, aâ”œâ–’os mâ”œأ­s tarde serâ”œآ،a prolongada la calle de la Torre, que en esta dâ”œآ®cada todavâ”œآ،a terminaba en la calle de Manuela Sancho. Al fondo se destacan el â”œأ­bside y la torre de la iglesia de San Miguel de los Navarros. A la izquierda, â”œأ­rboles de la ribera del râ”œآ،o Huerva. A la derecha, talleres Vulcan para reparaciâ”œâ”‚n de cubiertas y câ”œأ­maras, que antes estuvieran ubicados en la calle de San Miguel. Este entorno fue utilizado como aparcamiento hasta bien entrados los aâ”œâ–’os 70, como atestiguan los vehâ”œآ،culos estacionados en baterâ”œآ،a. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64921800, -0.87468900, '0101000020E6100000607825C973FDEBBFBDFC4E9319D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14777774729.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14777774729.webp', 'https://www.flickr.com/photos/zaragozaantigua/14777774729/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22047, 'Iglesia de San Miguel c.1955', 'La iglesia de San Miguel, en una luminosa imagen tomada desde la antigua Ronda o paseo de la Mina. Tras el arbolado, la plaza de San Miguel, y a la derecha, el emboque a la calle de la Reconquista. Muy cerca de donde estuviera la desaparecida puerta del Duque de la Victoria transita un coche motor de la serie 100, posiblemente en servicio en la tranviaria lâ”œآ،nea 1. Bajo Aragâ”œâ”‚n, encaminado hacia el inmediato puente de San Josâ”œآ®. Dos personas aprovechan la agradable solanera, o brasero natural, junto a la tapia del complejo parroquial. Fuente visual: Archivo Coyne, AHPZ.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64905700, -0.87643300, '0101000020E61000004C530438BD0BECBFB41EBE4C14D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14863305546.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14863305546.webp', 'https://www.flickr.com/photos/zaragozaantigua/14863305546/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
