INSERT INTO public.photos VALUES (22191, 'Aniversario de los Sitios 1958', 'Cartel diseâ”œâ–’ado por Antonio Margalâ”œآ®, 1958. El 150 aniversario de los Sitios de Zaragoza (1808 y 1809), dio para que el aâ”œâ–’o 1958 estuviese plagado de celebraciones conmemorativas, por parte de las autoridades locales franquistas. Se trataba de rememorar los hechos de la Guerra de la Independencia efectuando un paralelismo con la derrota de la democracia en la Guerra Civil de 1936-1939, dâ”œأ­ndoles a ambas el cariz de cruzada catâ”œâ”‚lica. En el cartel, el monumento a los Sitios de la plaza de Josâ”œآ® Antonio, el laurel como sâ”œآ،mbolo de la victoria, una composiciâ”œâ”‚n con destacadas torres de la ciudad, y la puerta del Carmen. Fuente visual: www.todocoleccion.net', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.64898700, -0.87944600, '0101000020E6100000F22213F06B24ECBFBB438A0112D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32503259592.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32503259592.webp', 'https://www.flickr.com/photos/zaragozaantigua/32503259592/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22204, 'Plaza Josâ”œآ® Antonio aâ”œâ–’os 50', 'Vista de la plaza de Josâ”œآ® Antonio nevada, con el Quiosco de la Mâ”œâ•‘sica en primer plano y el monumento a los Sitios a la derecha. Al fondo a la izquierda, la calle de Felipe Sanclemente. Fuente visual: Foto Serrano', 1950, 1950, 1959, 'Anos 50', 'CENTRO', 41.64866600, -0.87948500, '0101000020E610000069520ABABD24ECBF7903CC7C07D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37932736146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37932736146.webp', 'https://www.flickr.com/photos/zaragozaantigua/37932736146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22207, 'Râ”œآ،o Huerva 1951', 'El cauce del râ”œآ،o Huerva con el puente de San Josâ”œآ® al fondo, vistos desde la calle del Asalto. A la izquierda y tras los â”œأ­rboles de la ribera, explanada donde estuvieron los tendederos del lavadero Hondo. Por encima y tras la calle de Miguel Servet, esquinero edificio de la fâ”œأ­brica de pastas para sopa de Pedro Maldonado. A la derecha, justo antes del espacio ocupado por los almacenes de canterâ”œآ،a del Ayuntamiento, restos del pretil en piedra del provisional puente sobre el Huerva de mediados del siglo XIX, ubicado casi a medio camino entre el construido en el siglo XVI, que quedaba mâ”œأ­s hacia la izquierda, ya fuera de plano, y el moderno puente que centra la imagen. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64912400, -0.87455900, '0101000020E6100000D384ED2763FCEBBF3C86C77E16D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40559323341.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40559323341.webp', 'https://www.flickr.com/photos/zaragozaantigua/40559323341/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22370, 'Plaza Josâ”œآ® Antonio 1967', 'Vista aâ”œآ®rea de la plaza de Josâ”œآ® Antonio. En enero de 1968 el quiosco de la mâ”œâ•‘sica serâ”œأ­ desmontado y llevado al parque Primo de Rivera. Fuente: www.facebook.com/photo.php?fbid=10203623723993496&set...', 1967, 1967, 1967, 'Anos 60', 'CENTRO', 41.64886500, -0.87931300, '0101000020E610000022533E045523ECBF704221020ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21649774158.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21649774158.webp', 'https://www.flickr.com/photos/zaragozaantigua/21649774158/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22433, 'Vista aâ”œآ®rea plaza Josâ”œآ® Antonio 1967', 'Vista aâ”œآ®rea desde las inmediaciones de la plaza de Josâ”œآ® Antonio (abajo). Al fondo se distingue el puente del Ferrocarril de la Almozara sobre el Ebro. Fuente: "Zaragoza viva" (1969).', 1967, 1967, 1967, 'Anos 60', 'CENTRO', 41.64892600, -0.87944400, '0101000020E6100000C53A55BE6724ECBF16C3D50110D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30034455051.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30034455051.webp', 'https://www.flickr.com/photos/zaragozaantigua/30034455051/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22706, 'San Miguel 1971', 'Imagen capturada junto a la puerta de ingreso a la iglesia parroquial de San Miguel de los Navarros, durante la salida de un canâ”œâ”‚nico enlace matrimonial realizado segâ”œâ•‘n la liturgia catâ”œâ”‚lica, todo un tratado visual de antropologâ”œآ،a social de la â”œآ®poca. El estallido en rojo del vehâ”œآ،culo desestabiliza el cromatismo preponderante del conjunto, mayormente en tonos azules, y casi le roba el protagonismo a la blanca novia. A la izquierda, aspecto parcial de una de las construcciones adosadas al â”œأ­bside y cuerpo lateral de la iglesia, justo antes de la intervenciâ”œâ”‚n realizada desde la Direcciâ”œâ”‚n General de Bellas Artes del Ministerio de Educaciâ”œâ”‚n, consistente en su derribo, y en la restauraciâ”œâ”‚n de la ornamentaciâ”œâ”‚n exterior original. Este proyecto fue dirigido por el arquitecto Fernando Chueca Goitia. Fuente visual: Patti Larson Photo, en www.flickr.com', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.64970900, -0.87655500, '0101000020E610000022A64412BD0CECBF5C751DAA29D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27823530771.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27823530771.webp', 'https://www.flickr.com/photos/zaragozaantigua/27823530771/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22789, 'San Miguel 1971', 'Dibujo representando el alzado de la fachada principal de la iglesia parroquial de San Miguel de los Navarros, recayente a la homâ”œâ”‚nima plaza, tal y como hubiera quedado de haberse realizado de forma integral la restauraciâ”œâ”‚n proyectada por el arquitecto Fernando Chueca Goitia. Destaca la reinterpretaciâ”œâ”‚n de la torre mudâ”œآ®jar, posiblemente influida por la reciente intervenciâ”œâ”‚n en la iglesia de la Magdalena y que pretendâ”œآ،a ajustarse a su supuesto estado original. En este caso, el metâ”œأ­lico y caracteristico chapitel modernista figura como remate de un campanario de nueva planta levantado a la derecha de la escultâ”œâ”‚rica portada de ingreso. Fuente visual: Ascensiâ”œâ”‚n Hernâ”œأ­ndez Martâ”œآ،nez, La intervenciâ”œâ”‚n del arquitecto Fernando Chueca Goitia en la iglesia de San Miguel de los Navarros, Zaragoza (1971-1978), IFC, 2013.', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.64968000, -0.87656900, '0101000020E610000061FF756EDA0CECBFC16ED8B628D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40264335484.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40264335484.webp', 'https://www.flickr.com/photos/zaragozaantigua/40264335484/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22932, 'Calle de San Miguel 1981', 'Imagen del antiguo edificio nâ”¬â•‘ 38-40 de la calle de San Miguel, chaflanero con la calle de Sancho y Gil (a la derecha), una antigualla provinciana que, en el momento de fotografiarla, ya estaba en trâ”œأ­nsito hacia la nada edilicia. Fuente visual: foto de R. Benedicto, en "Andalâ”œأ­n, periâ”œâ”‚dico quincenal aragonâ”œآ®s".', 1981, 1981, 1981, 'Anos 80', 'CENTRO', 41.65002100, -0.87789600, '0101000020E61000004241295AB917ECBF4B5B5CE333D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31837160053.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31837160053.webp', 'https://www.flickr.com/photos/zaragozaantigua/31837160053/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23572, 'Calle del Heroâ”œآ،smo 1930', 'Imagen del final de la calle del Heroâ”œآ،smo, aproximadamente en el punto donde estuviera ubicada la desaparecida Puerta Quemada, que daba nombre a esa calle hasta los asedios de 1808-09. A la izquierda, vista parcial del nâ”¬â•‘ 28 de la calle de la Reconquista. Al fondo, esquinero, el nâ”¬â•‘ 1 de la calle de Manuela Sancho, y a la derecha, el nâ”¬â•‘ 53 y el nâ”¬â•‘ 55 de Heroâ”œآ،smo. La captura se ha realizado desde la calle del Asalto, cerca de los almacenes municipales de canterâ”œآ،a inmediatos al puente de San Josâ”œآ®. Un grupo de vecinos, muy interesados en el histâ”œâ”‚rico emplazamiento, posan amablemente ante el objetivo. Fuente visual: Miguel Marâ”œآ،n Chivite, periâ”œâ”‚dico "Heraldo de Aragâ”œâ”‚n".', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.64932400, -0.87510700, '0101000020E610000081053065E000ECBF0341800C1DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31698729224.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31698729224.webp', 'https://www.flickr.com/photos/zaragozaantigua/31698729224/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24115, 'Calle de San Miguel 1959', 'Imagen capturada durante la celebraciâ”œâ”‚n del segundo aniversario de la Cooperativa de Vendedores de Prensa, Revistas y Publicaciones Nacionales, en este caso en la "animada fiesta" que tuvo lugar en los locales de la Cooperativa, sitos en el nâ”¬â•‘ 22 de la calle de San Miguel, como continuaciâ”œâ”‚n menos formal y distendida a la comida de hermandad para un centenar de comensales presidida por el delegado provincial de Sindicatos y procurador en Cortes, Isaâ”œآ،as Monforte Extremiana y otros altos cargos locales del sector del papel, prensa y artes grâ”œأ­ficas, que contâ”œâ”‚ con la asistencia de delegados de otras provincias. A la izquierda de la fila central, Antonio Nasarre de Letosa Sieso, uno de los veteranos fundadores de la Cooperativa, y Antonio Nasarre de Letosa Gimâ”œآ®nez de Bagâ”œâ•‌â”œآ®s, presidente de la misma.', 1959, 1959, 1959, 'Anos 50', 'CENTRO', 41.65043600, -0.87927100, '0101000020E61000006747AAEFFC22ECBF0E12A27C41D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52164944009.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52164944009.webp', 'https://www.flickr.com/photos/zaragozaantigua/52164944009/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24133, 'Mosaico Santa Engracia 1907', 'Fotografâ”œآ،a de un mosaico romano del siglo IV, el de fecha mâ”œأ­s reciente hallado en Zaragoza. Decoraba el suelo a dos alturas de un dormitorio, en una finca extramuros de la colonia. Estâ”œأ­ en la Huerta de Santa Engracia, y fue descubierto al remover la zona para instalar la Exposiciâ”œâ”‚n Hispano Francesa de 1908. Archivo fotogrâ”œأ­fico del Museo de Zaragoza.', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64886500, -0.87931300, '0101000020E610000022533E045523ECBF704221020ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19156909996.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19156909996.webp', 'https://www.flickr.com/photos/zaragozaantigua/19156909996/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24136, 'Medalla Exposiciâ”œâ”‚n Hispano Francesa 1908', 'Reverso de la Medalla de Bronce de la Exposiciâ”œâ”‚n Hispano Francesa de Zaragoza, 1908. Medalla de 6 cm. acuâ”œâ–’ada por la casa Anduiza de Bilbao. En el anverso figuran los reyes Alfonso XIII y Victoria Eugenia; el reverso muestra una vista panorâ”œأ­mica de la Exposiciâ”œâ”‚n, con el escudo de Zaragoza en la parte inferior y el exergo sin acuâ”œâ–’ar, para grabar el nombre del expositor premiado con ella. Fuente visual: www.museunacional.cat/', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64886500, -0.87931300, '0101000020E610000022533E045523ECBF704221020ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19425600470.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19425600470.webp', 'https://www.flickr.com/photos/zaragozaantigua/19425600470/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24142, 'Inauguraciâ”œâ”‚n Expo 1908', 'La Exposiciâ”œâ”‚n Hispano-Francesa de Zaragoza de 1908, en conmemoraciâ”œâ”‚n del Centenario de los Sitios, fue oficialmente inaugurada el dâ”œآ،a 1â”¬â•‘ de mayo de ese aâ”œâ–’o mediante una ceremonia para la que se habâ”œآ،a levantado un "altar" coronado cerca del Paseo de la Mina. Allâ”œآ،, el infante real D. Carlos estaba en representaciâ”œâ”‚n "especialâ”œآ،sima" de S. M. el Rey Alfonso XIII. Numerosas y altâ”œآ،simas personalidades, representantes de todas las instituciones, el ejâ”œآ®rcito, la Iglesia, y la nobleza de los alrededores, casi no cabâ”œآ،an en el espacio habilitado, separado del vulgo. El turno de los discursos fue inaugurado por el Arzobispo (el inefable Juan Soldevila y Romero), al que siguieron Basilio Paraâ”œآ،so (por el Comitâ”œآ® de Organizaciâ”œâ”‚n del Certamen), el Alcalde (Antonio Fleta) y el Ministro de Fomento (Augusto Gonzâ”œأ­lez Besada), antes de culminar con el del Infante, que tras concluir la lectura del mismo declarâ”œâ”‚ abierta la Exposiciâ”œâ”‚n, en nombre del Rey. Para escenificar mâ”œأ­s teatralmente la buena nueva, el secretario de la sociedad Colombâ”œâ”‚fila de Barcelona soltâ”œâ”‚ mâ”œأ­s de 300 palomas que tomaron el camino hacia la ciudad condal para confirmar con su vuelo que la Exposiciâ”œâ”‚n estaba inaugurada. En la Imagen se ha capturado un instante de la intervenciâ”œâ”‚n del Infante D. Carlos (acompaâ”œâ–’ado, a nuestra derecha, por el infante Don Luis Alfonso de Orleâ”œأ­ns, con sombrero de copa, aunque descubierto) en el ceremonial "Altar" instalado en la esquina del edificio de "La Caridad", que como parte integrante de los temporales pabellones de la Expo, fue "Palacio de Industrias". Actualmente en esta esquina confluyen la plaza de los Sitios y la calle Moret. Fuente visual: Foto Escolâ”œأ­, para la revista "Mercurio".', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64865700, -0.87858400, '0101000020E6100000603E59315C1DECBF26A94C3107D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20212694702.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20212694702.webp', 'https://www.flickr.com/photos/zaragozaantigua/20212694702/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24144, 'Edificio de las Escuelas 1907', 'Foto: Escolâ”œأ­. Construcciâ”œâ”‚n del edificio de las Escuelas de la Exposiciâ”œâ”‚n Hispano Francesa de 1908, proyectado por el arquitecto Fâ”œآ®lix Navarro. Al fondo a la izquierda emerge el remate de la torre de la iglesia parroquial de San Miguel de los Navarros.', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64894500, -0.87853000, '0101000020E610000094C151F2EA1CECBF8CF337A110D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21019568776.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21019568776.webp', 'https://www.flickr.com/photos/zaragozaantigua/21019568776/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24150, 'Proyecto Exposiciâ”œâ”‚n Hispano-Francesa 1907', '"Proyecto de la Exposiciâ”œâ”‚n Hispano-Francesa que debe celebrarse en Zaragoza de mayo a octubre de 1908. Vista general segâ”œâ•‘n el proyecto. Edificios principales en construcciâ”œâ”‚n". Ilustraciâ”œâ”‚n que refleja el recinto de la muestra, en la Huerta de Santa Engracia, con detalle numerado de sus hitos, el râ”œآ،o Huerva rodeâ”œأ­ndolo a la derecha y las casas de la calle de San Miguel arriba a la izquierda. Fuente: Diario ABC, 5 de diciembre de 1907.', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64893400, -0.87938900, '0101000020E6100000E2C96E66F423ECBF98A1F14410D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25835661307.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25835661307.webp', 'https://www.flickr.com/photos/zaragozaantigua/25835661307/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24153, 'Huerta de Santa Engracia 1907', 'Imagen capturada en los terrenos de la antigua huerta de Santa Engracia durante las obras de construcciâ”œâ”‚n de los pabellones y edificios proyectados en el interior del recinto de la Exposiciâ”œâ”‚n Hispano-Francesa de 1908. La fotografâ”œآ،a se habrâ”œآ،a realizado desde las traseras del edificio proyectado como "Escuelas". Al fondo, la iglesia parroquial de Santa Engracia. A la izquierda, arboleda ribereâ”œâ–’a del râ”œآ،o Huerva junto al paseo de la Mina. Fuente visual: "Libro de Oro. Exposiciâ”œâ”‚n Hispano-Francesa de 1908".', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64894500, -0.87853000, '0101000020E610000094C151F2EA1CECBF8CF337A110D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30102769487.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30102769487.webp', 'https://www.flickr.com/photos/zaragozaantigua/30102769487/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24157, 'Inauguraciâ”œâ”‚n Exposiciâ”œâ”‚n 1908', 'El arzobispo Juan Soldevila Romero oficia en un altar de campaâ”œâ–’a la inauguraciâ”œâ”‚n de la Exposiciâ”œâ”‚n Hispano-Francesa, el 1 de mayo de ese aâ”œâ–’o, junto al edificio de Artes e Industrias. Al fondo, el Jardâ”œآ،n Botâ”œأ­nico. Fuente visual: La Ilustraciâ”œâ”‚n Artâ”œآ،stica (BCN)', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64867700, -0.87861800, '0101000020E610000065A9F57EA31DECBF6D5512D907D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32431400223.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32431400223.webp', 'https://www.flickr.com/photos/zaragozaantigua/32431400223/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24158, 'Templete 1908', 'Foto: Aurelio Grasa. Templete en la futura calle de Moret, desde el que se inaugurâ”œâ”‚ la Exposiciâ”œâ”‚n Hispano-Francesa de 1908. A la izquierda, el Edificio de Artes e Industrias, y a la derecha, el Edificio Museos. Fuente: Archivo Barboza-Grasa, a travâ”œآ®s de Heraldo de Aragâ”œâ”‚n.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64871800, -0.87870400, '0101000020E610000009A9DBD9571EECBFCC29013109D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32686609792.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32686609792.webp', 'https://www.flickr.com/photos/zaragozaantigua/32686609792/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24160, 'Huerta de Santa Engracia c.1907', 'Despejada imagen panorâ”œأ­mica de la antigua huerta de Santa Engracia, capturada a ras de suelo durante las obras de nivelaciâ”œâ”‚n del terreno para el inicio de las obras de construcciâ”œâ”‚n del recinto de la Exposiciâ”œâ”‚n Hispano-Francesa de 1908. Fue en este lugar donde volviâ”œâ”‚ a ver la luz un mosaico tardorromano datado en el siglo IV, posiblemente de una villa de la periferia agrâ”œآ،cola de la ciudad. A la izquierda, la iglesia de Santa Engracia y, adosado, los restos del cuartel homâ”œâ”‚nimo. A la derecha, la câ”œâ•‘pula de la antigua iglesia de San Ildefonso, convertida recientemente en parroquia de Santiago el Mayor. Entre ambas iglesias, las traseras orientales de la calle de la Independencia. Fuente visual: "Zaragoza 1908-2008. Arquitectura y Urbanismo".', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64898700, -0.87944600, '0101000020E6100000F22213F06B24ECBFBB438A0112D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33340525010.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33340525010.webp', 'https://www.flickr.com/photos/zaragozaantigua/33340525010/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
