INSERT INTO public.photos VALUES (24277, 'Alfonso XIII 1908', '28 de octubre de 1908. El rey Alfonso XIII preside, junto a su esposa Victoria Eugenia, la inauguraciâ”œâ”‚n del monumento a Los Sitios, situado hoy en el centro de la plaza del mismo nombre.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64890300, -0.87926500, '0101000020E6100000DE8E705AF022ECBF5DA3E5400FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14966488561.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14966488561.webp', 'https://www.flickr.com/photos/zaragozaantigua/14966488561/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24279, '&quot;Edificio de Artes e Industrias&quot; 1908', 'AHPZ. Archivo Coyne. Ignacio Coyne. 1908. La Escuela de Artes y Oficios de Zaragoza se habâ”œآ،a inaugurado en 1895, en la antigua Facultad de Medicina y Ciencias. En 1908 se trasladâ”œâ”‚ a la plaza de Castelar, a un edificio que habâ”œآ،a formado parte de la Exposiciâ”œâ”‚n Hispano-Francesa, denominado "Edificio de Artes e Industrias", y que tras la muestra fue redenominado como "Escuelas de Industrias y Bellas Artes, de Comercio y de Artes y Oficios". La imagen parece clara en varios aspectos, todos ellos desaparecidos luego: contaba desde el principio con su propia valla de forja; pinturas alusivas a las artes y oficios decoraban secciones de los muros de la fachada principal; una galerâ”œآ،a de pequeâ”œâ–’as reproducciones de la Tour Eiffel aireaban la estructura.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64894500, -0.87853000, '0101000020E610000094C151F2EA1CECBF8CF337A110D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15021312272.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15021312272.webp', 'https://www.flickr.com/photos/zaragozaantigua/15021312272/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24282, 'Josephine Baker 1930', 'A mediados del mes de marzo de 1930, mientras el Ebro se salâ”œآ،a de madre de forma tremenda, la Sociedad Anâ”œâ”‚nima General de Espectâ”œأ­culos propiciâ”œâ”‚ la actuaciâ”œâ”‚n en el Teatro-Cine Parisiana de Zaragoza de la "Venus de â”œآ®bano", la "Artista mundial", la "Danzarina de los ritmos exâ”œâ”‚ticos" la afronorteamericana de 23 aâ”œâ–’os de edad Freda Josephine Baker Carson, de nombre artâ”œآ،stico Josephine Baker. Completaban el espectâ”œأ­culo nâ”œâ•‘meros de Moritz, "Bailarâ”œآ،n excâ”œآ®ntrico americano"; Conchita de Leonardo, "Notabilâ”œآ،sima cancionista"; Pompoff-Thedy, "Famosos clowns musicales"; Lina Jack et Farbell, "Câ”œآ®lebre pareja de bailes acrobâ”œأ­ticos"; Custodia Romero, "La Venus de bronce"; y "La formidable orquesta" Manhatam (sic) Players. A las previstas funciones dobles (18:15 y 22.15 h.) de los dâ”œآ،as 14 y 15 se le aâ”œâ–’adiâ”œâ”‚ de forma excepcional una tercera jornada el dâ”œآ،a 16, domingo, cuya â”œâ•‘ltima funciâ”œâ”‚n incluyâ”œâ”‚ una "Serenata d''onore a la Venus de â”œآ®bano", un "Cuadro de Jota" integrado por Lazarito y Maruja Esteso, Marâ”œآ،a Asensio, Juan Antonio Gracia y Josâ”œآ® Esteso, y una lectura de cuartillas titulado "Homenaje de Zaragoza a Josefina Baker". En la imagen, posado de Josephine Baker a los pies del Monumento a los Sitios en la plaza de Castelar. En 1936 adquiriâ”œâ”‚ la ciudadanâ”œآ،a francesa, y durante la Segunda Guerra Mundial ejerciâ”œâ”‚ de agente del espionaje francâ”œآ®s ("le Deuxiâ”œآ؟me Bureau"), filtrando informaciâ”œâ”‚n a los Aliados de movimientos de tropas del Eje, y pudo hacerse con un libro de câ”œâ”‚digos y claves italo-alemanas. En febrero de 1973, con 66 aâ”œâ–’os de edad, Josephine Baker regresâ”œâ”‚ a Zaragoza para actuar en la sala "Cancela". Falleciâ”œâ”‚ dos aâ”œâ–’os mâ”œأ­s tarde. Fuente visual: foto Marâ”œآ،n Chivite, en "Instantâ”œأ­neas zaragozanas", CAZAR, 1982.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.64883900, -0.87928700, '0101000020E6100000D388997D1E23ECBF47AF06280DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15158126822.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15158126822.webp', 'https://www.flickr.com/photos/zaragozaantigua/15158126822/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24284, 'Santa Catalina 1808', '"Vista del costado de la iglesia de las monjas de Santa Catalina". Serie Ruinas de Zaragoza, de Juan Gâ”œأ­lvez (dibujo) y Fernando Brambila (grabado), Câ”œأ­diz, 1812. La iglesia del monasterio de monjas clarisas o dueâ”œâ–’as menoretas de Santa Catalina, el cenobio femenino mâ”œأ­s antiguo de Zaragoza, resultâ”œâ”‚ bastante daâ”œâ–’ada en los Sitios. Ademâ”œأ­s, a principios del siglo XX se derribâ”œâ”‚ por motivos urbanâ”œآ،sticos lo que todavâ”œآ،a se mantenâ”œآ،a en pie, cayendo la interesante Sala Capitular. Reconstruidos convento e iglesia, permanecen en la esquina de las calles Arquitecto Magdalena y San Miguel. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.65028900, -0.87892500, '0101000020E6100000AA6054522720ECBF6AF981AB3CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15265014931.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15265014931.webp', 'https://www.flickr.com/photos/zaragozaantigua/15265014931/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25635, 'Av. de Juan Carlos I 2005', 'Imagen capturada desde la altura del nâ”¬â•‘ 25 de la avenida de Gâ”œâ”‚mez Laguna durante la gran nevada de finales de febrero de 2005, con buena visual del solar comprendido entre las avenidas de Juan Carlos I (izquierda) y Juan Pablo II (derecha). Al fondo, tras la avenida de Ramâ”œâ”‚n Sainz de Varanda, el Centro de Formaciâ”œâ”‚n Juan Pablo II de una conocida entidad de ahorro local hoy desaparecida. En este solar serâ”œآ،a construido mâ”œأ­s tarde el gran complejo del Centro comercial Aragonia, inaugurado en 2009. Fuente visual: foto Sergi en www.flickr.com/photos/sergutel/2279394715/in/album-721576...', 2005, 2005, 2005, 'Siglo XXI', 'UNIVERSIDAD', 41.64018700, -0.90920600, '0101000020E610000096766A2E3718EDBF8429CAA5F1D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42730837162.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42730837162.webp', 'https://www.flickr.com/photos/zaragozaantigua/42730837162/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
